&lt;ul&gt;
&lt;li&gt;&lt;span data-contrast=&quot;auto&quot;&gt;Setup&amp;nbsp;and&amp;nbsp;operate&amp;nbsp;multi-axis CNC mills and lathes, including 3-, 4-, and 5-axis equipment&lt;/span&gt;&lt;span data-ccp-props=&quot;{}&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span data-contrast=&quot;auto&quot;&gt;Perform complete setups including tooling, offsets,&amp;nbsp;workholding, and prove-outs&lt;/span&gt;&lt;span data-ccp-props=&quot;{}&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span data-contrast=&quot;auto&quot;&gt;Machine complex, tight-tolerance aerospace components from a variety of materials&lt;/span&gt;&lt;span data-ccp-props=&quot;{}&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span data-contrast=&quot;auto&quot;&gt;Interpret blueprints, GD&amp;amp;T, models, and work instructions to complete machining operations&lt;/span&gt;&lt;span data-ccp-props=&quot;{}&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span data-contrast=&quot;auto&quot;&gt;Support prototype and short-run production machining&lt;/span&gt;&lt;span data-ccp-props=&quot;{}&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span data-contrast=&quot;auto&quot;&gt

